
.status-card {
  position: relative;
  width: 100%;
  max-width: 380px;
  margin: 0 auto;
  font-family: var(--font-mono);
  color: var(--c-text);
  font-size: 11px;
  line-height: 1.45;
  border: 1px solid var(--c-border);
  border-radius: 10px;
  overflow: hidden;
}

.wave-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  background:
    radial-gradient(ellipse at 20% 80%, rgba(180, 40, 40, 0.25) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(200, 60, 60, 0.15) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 50%, rgba(140, 20, 20, 0.3) 0%, transparent 70%),
    linear-gradient(180deg, var(--c-bg-deep) 0%, var(--c-bg-mid) 50%, var(--c-bg-deep) 100%);
  background-size: 200% 200%;
  animation: waveFlow 8s ease-in-out infinite;
}

@keyframes waveFlow {
  0%, 100% {
    background-position: 0% 0%;
  }
  25% {
    background-position: 100% 30%;
  }
  50% {
    background-position: 50% 100%;
  }
  75% {
    background-position: 0% 70%;
  }
}

.card-content {
  position: relative;
  z-index: 1;
}

.time-section {
  padding: 12px 16px 8px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.time-value {
  font-weight: bold;
  font-size: 0.85rem;
  letter-spacing: 0.5px;
}

.stats-section {
  padding: 6px 16px 14px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.stat-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-header {
  display: flex;
  align-items: center;
  gap: 6px;
}

.stat-icon {
  font-size: 0.85rem;
  width: 16px;
  text-align: center;
}

.stat-name {
  font-weight: bold;
  font-size: 0.75rem;
  min-width: 36px;
  color: var(--c-text-dim);
}

.stat-num {
  font-weight: bold;
  font-size: 0.75rem;
  min-width: 24px;
  text-align: right;
}

.stat-tag {
  font-size: 0.6rem;
  font-weight: bold;
  padding: 1px 5px;
  border-radius: 3px;
  border: 1px solid;
  letter-spacing: 0.5px;

  &.high {
    color: var(--c-food-high);
    border-color: var(--c-food-high);
    background: rgba(78, 203, 113, 0.08);
  }

  &.mid {
    color: var(--c-food-mid);
    border-color: var(--c-food-mid);
    background: rgba(212, 168, 67, 0.08);
  }

  &.low {
    color: var(--c-food-low);
    border-color: var(--c-food-low);
    background: rgba(224, 85, 69, 0.08);
  }
}

.stat-bar {
  height: 4px;
  border-radius: 2px;
  background: rgba(255, 255, 255, 0.06);
  overflow: hidden;
}

.stat-bar-inner {
  height: 100%;
  border-radius: 2px;
  transition: width 0.35s ease;

  &.high { background: var(--c-food-high); }
  &.mid  { background: var(--c-food-mid); }
  &.low  { background: var(--c-food-low); }
}

.stat-hint {
  font-size: 0.6rem;
  color: var(--c-text-dim);
  padding-left: 22px;
}

@media (max-width: 400px) {
  .status-card {
    max-width: 100%;
  }

  .stat-header {
    flex-wrap: wrap;
  }
}
